def token_case(s):
    """
    Converts underscore-delimited identifier to camel case.

    :param s: string containing underscore-delimited tokens
    :return: string in camel case format
    """
    exceptions = ['URL', 'ID']
    tokens = s.split('_')

    if len(tokens) == 1 and tokens[0] in exceptions:
        return tokens[0].upper()

    result = [tokens[0].lower()]
    for token in tokens[1:]:
        if token not in exceptions:
            result.append(token.capitalize())
        else:
            result.append(token)

    return ''.join(result)
